import{_ as a,o as t,c as o,ae as r}from"./chunks/framework.BAOUhEwF.js";const u=JSON.parse('{"title":"Type Alias: ThAttrs","description":"","frontmatter":{},"headers":[],"relativePath":"api/ts/elements/table/th/type-aliases/ThAttrs.md","filePath":"api/ts/elements/table/th/type-aliases/ThAttrs.md"}'),s={name:"api/ts/elements/table/th/type-aliases/ThAttrs.md"};function l(i,e,c,n,d,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<p><a href="./../../../../README.html"><strong>@vastare/fundatio v1.0.1</strong></a></p><hr><h1 id="type-alias-thattrs" tabindex="-1">Type Alias: ThAttrs <a class="header-anchor" href="#type-alias-thattrs" aria-label="Permalink to &quot;Type Alias: ThAttrs&quot;">​</a></h1><blockquote><p><strong>ThAttrs</strong> = <code>Omit</code>&lt;<a href="./../../../../ts/dom/type-aliases/GlobalAttrs.html"><code>GlobalAttrs</code></a>, <code>&quot;aria&quot;</code>&gt; &amp; <code>object</code></p></blockquote><p>Defined in: <a href="https://github.com/VastareDev/fundatio/blob/7baf5196c24e02fa3730a12e562441cdd5585421/src/elements/table/th/index.ts#L106" target="_blank" rel="noreferrer">elements/table/th/index.ts:106</a></p><p>Attribute bag for th creation/enhancement.</p><h2 id="type-declaration" tabindex="-1">Type Declaration <a class="header-anchor" href="#type-declaration" aria-label="Permalink to &quot;Type Declaration&quot;">​</a></h2><h3 id="abbr" tabindex="-1">abbr? <a class="header-anchor" href="#abbr" aria-label="Permalink to &quot;abbr?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>abbr</strong>: <code>string</code></p></blockquote><p>Alternative label for the header cell.</p><h4 id="remarks" tabindex="-1">Remarks <a class="header-anchor" href="#remarks" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Useful when the visible header text is long but needs a shorter label in other contexts (e.g. when referenced as a header).</p><h3 id="aria" tabindex="-1">aria? <a class="header-anchor" href="#aria" aria-label="Permalink to &quot;aria?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>aria</strong>: <a href="./StructuredAria.html"><code>StructuredAria</code></a></p></blockquote><p>Structured ARIA fields mapped into <code>aria-*</code> attributes.</p><h3 id="colspan" tabindex="-1">colspan? <a class="header-anchor" href="#colspan" aria-label="Permalink to &quot;colspan?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>colspan</strong>: <code>number</code></p></blockquote><p>Number of columns the cell spans.</p><h4 id="remarks-1" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-1" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Must be a positive integer to be meaningful. Fundatio sets the attribute only when you provide a finite value greater than 0.</p><h3 id="headers" tabindex="-1">headers? <a class="header-anchor" href="#headers" aria-label="Permalink to &quot;headers?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>headers</strong>: <code>string</code></p></blockquote><p>Space-separated IDs of <code>&lt;th&gt;</code> elements that apply to this cell.</p><h4 id="remarks-2" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-2" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>This is primarily used for complex tables where <code>scope</code> is insufficient. Fundatio does not validate ID existence; consumers control their DOM trees.</p><h3 id="rowspan" tabindex="-1">rowspan? <a class="header-anchor" href="#rowspan" aria-label="Permalink to &quot;rowspan?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>rowspan</strong>: <code>number</code></p></blockquote><p>Number of rows the cell spans.</p><h4 id="remarks-3" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-3" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Must be a positive integer to be meaningful. Fundatio sets the attribute only when you provide a finite value greater than 0.</p><h3 id="scope" tabindex="-1">scope? <a class="header-anchor" href="#scope" aria-label="Permalink to &quot;scope?&quot;">​</a></h3><blockquote><p><code>optional</code> <strong>scope</strong>: <a href="./ThScope.html"><code>ThScope</code></a></p></blockquote><p>Indicates which cells the header cell applies to.</p><h4 id="remarks-4" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-4" aria-label="Permalink to &quot;Remarks&quot;">​</a></h4><p>Use for simple row/column headers. For complex tables, prefer <code>headers</code>.</p><h2 id="remarks-5" tabindex="-1">Remarks <a class="header-anchor" href="#remarks-5" aria-label="Permalink to &quot;Remarks&quot;">​</a></h2><p>Th elements accept standard HTML global attributes, plus:</p><ul><li><code>abbr</code>: an alternative label for the header cell (often abbreviated)</li><li><code>colspan</code>: number of columns the cell spans</li><li><code>rowspan</code>: number of rows the cell spans</li><li><code>headers</code>: space-separated IDs of <code>&lt;th&gt;</code> elements that apply to this cell</li><li><code>scope</code>: indicates the set of cells this header applies to (<code>row</code>, <code>col</code>, etc.)</li></ul><p>Fundatio also supports a structured ARIA input for common ARIA fields, which is mapped into <a href="./../../../../ts/dom/type-aliases/GlobalAttrs.html#aria">GlobalAttrs.aria</a> without changing Fundatio&#39;s core DOM helpers.</p><p>Security notes:</p><ul><li>Inline event handler attributes (e.g. <code>onclick</code>) are blocked by <code>dom.ts</code>.</li><li>The raw <code>style</code> attribute is blocked; use <a href="./../../../../ts/dom/type-aliases/GlobalAttrs.html#style">GlobalAttrs.style</a> instead.</li></ul>',41)])])}const b=a(s,[["render",l]]);export{u as __pageData,b as default};
